{
    "level": "A1–A2",
    "intro": "In this topic you will learn how <strong>plural nouns</strong> are formed in English - the main rules and exceptions.",
    "rules": [
        {
            "label": "+ S",
            "color": "emerald",
            "text": "<strong>Adding -s</strong> - the main rule:",
            "example": "cat → cats, book → books, dog → dogs"
        },
        {
            "label": "+ ES",
            "color": "blue",
            "text": "<strong>Adding -es</strong> — after s, x, z, ch, sh:",
            "example": "box → boxes, bus → buses, watch → watches"
        },
        {
            "label": "Y → IES",
            "color": "amber",
            "text": "<strong>Replacing y with ies</strong> — after a consonant:",
            "example": "baby → babies, city → cities, party → parties"
        }
    ]
}

{
    "title": "1. The main ways to form the plural",
    "intro": "There are three main rules for forming the plural of English nouns:",
    "items": [
        {
            "label": "+ S",
            "title": "Add -s",
            "subtitle": "Most nouns are cat → cats, book → books"
        },
        {
            "label": "+ ES",
            "title": "Add -es",
            "subtitle": "After s, x, z, ch, sh — box → boxes, bus → buses"
        },
        {
            "label": "Y → IES",
            "title": "Y change to IES",
            "subtitle": "After a consonant — baby → babies, city → cities"
        }
    ]
}

{
    "title": "2. Rule 1: Adding -s",
    "sections": [
        {
            "label": "Basic rule",
            "color": "emerald",
            "description": "Most nouns form the plural by simple <strong>adding -s</strong>.",
            "examples": [
                {
                    "en": "cat → cats",
                    "ua": "cat → cats"
                },
                {
                    "en": "dog → dogs",
                    "ua": "dog → dogs"
                },
                {
                    "en": "book → books",
                    "ua": "book → books"
                },
                {
                    "en": "table → tables",
                    "ua": "table → tables"
                }
            ]
        },
        {
            "label": "After vowels",
            "color": "sky",
            "description": "After vowel letters (a, e, i, o, u) we simply add <strong>-s</strong>.",
            "examples": [
                {
                    "en": "bee → bees",
                    "ua": "bee → bees"
                },
                {
                    "en": "tree → trees",
                    "ua": "tree → trees"
                },
                {
                    "en": "shoe → shoes",
                    "ua": "boot → shoes"
                },
                {
                    "en": "zoo → zoos",
                    "ua": "zoo → zoos"
                }
            ]
        },
        {
            "label": "Pronunciation",
            "color": "amber",
            "description": "End <strong>-s</strong> is pronounced as [s], [z] or [ɪz] depending on the preceding sound.",
            "examples": [
                {
                    "en": "books [bʊks] is the [s]",
                    "ua": " sound after voiceless consonants"
                },
                {
                    "en": "dogs [dɒɡz] is the [z]",
                    "ua": " sound after voiced consonants and vowels"
                },
                {
                    "en": "buses [ˈbʌsɪz] - sound [ɪz]",
                    "ua": "after s, z, sh, ch, x"
                }
            ],
            "note": "📌 This is automatic - no special learning is required!"
        }
    ]
}

{
    "title": "3. Rule 2: Adding -es",
    "sections": [
        {
            "label": "After s, ss, x, z",
            "color": "blue",
            "description": "If the noun ends in <strong>s, ss, x, z</strong>, add <strong>-es</strong>.",
            "examples": [
                {
                    "en": "bus → buses",
                    "ua": "bus → buses"
                },
                {
                    "en": "glass → glasses",
                    "ua": "glass → glasses"
                },
                {
                    "en": "box → boxes",
                    "ua": "box → boxes"
                },
                {
                    "en": "quiz → quizzes",
                    "ua": "test → tests"
                }
            ]
        },
        {
            "label": "After ch, sh",
            "color": "sky",
            "description": "If the noun ends in <strong>ch or sh</strong>, we also add <strong>-es</strong>.",
            "examples": [
                {
                    "en": "watch → watches",
                    "ua": "clock → watches"
                },
                {
                    "en": "church → churches",
                    "ua": "church → churches"
                },
                {
                    "en": "dish → dishes",
                    "ua": "plate → plates"
                },
                {
                    "en": "brush → brushes",
                    "ua": "brush → brushes"
                }
            ]
        },
        {
            "label": "Why -es?",
            "color": "purple",
            "description": "Adding <strong>-es</strong> makes pronunciation easier after hissing and whistling sounds.",
            "examples": [
                {
                    "en": "box + s = boxes ✗ (hard to pronounce)",
                    "ua": "incorrect"
                },
                {
                    "en": "box + es = boxes ✓ [ˈbɒksɪz]",
                    "ua": "correct"
                }
            ],
            "note": "📌 This adds a syllable for ease of pronunciation!"
        }
    ]
}

{
    "title": "4. Rule 3: Y → IES",
    "sections": [
        {
            "label": "Consonant + Y",
            "color": "amber",
            "description": "If <strong>y</strong> is preceded by a <strong>consonant</strong>, change <strong>y to ies</strong>.",
            "examples": [
                {
                    "en": "baby → babies",
                    "ua": "baby → babies"
                },
                {
                    "en": "city → cities",
                    "ua": "city → cities"
                },
                {
                    "en": "party → parties",
                    "ua": "party → parties"
                },
                {
                    "en": "country → countries",
                    "ua": "country → countries"
                }
            ]
        },
        {
            "label": "Voice + y days",
            "color": "emerald",
            "description": "Якщо перед <strong>y</strong> стоїть <strong>голосна</strong> (a, e, i, o, u), просто додаємо <strong>-s</strong>.",
            "examples": [
                {
                    "en": "boy → boys",
                    "ua": "хлопчик → хлопчики"
                },
                {
                    "en": "day → days",
                    "ua": "день → дні"
                },
                {
                    "en": "key → keys",
                    "ua": "key → keys"
                },
                {
                    "en": "toy → toys",
                    "ua": "toy → toys"
                }
            ]
        },
        {
            "label": "How to remember?",
            "color": "sky",
            "description": "An easy way to remember the rule:",
            "examples": [
                {
                    "en": "Consonant + y → ies",
                    "ua": "baby → babies"
                },
                {
                    "en": "Vowel + y → ys",
                    "ua": "boy → boys"
                }
            ],
            "note": "📌 Look at the letter BEFORE y!"
        }
    ]
}

{
    "title": "5. Nouns in -o",
    "sections": [
        {
            "label": "Consonant + O → OES",
            "color": "purple",
            "description": "Some nouns in <strong>-o</strong> (after a consonant) add <strong>-es</strong>.",
            "examples": [
                {
                    "en": "tomato → tomatoes",
                    "ua": "tomato → tomatoes"
                },
                {
                    "en": "potato → potatoes",
                    "ua": "potato → potatoes"
                },
                {
                    "en": "hero → heroes",
                    "ua": "hero → heroes"
                },
                {
                    "en": "echo → echoes",
                    "ua": "echo → echo"
                }
            ]
        },
        {
            "label": "Vowel + O → OS",
            "color": "emerald",
            "description": "If <strong>-o</strong> is preceded by a vowel, just add <strong>-s</strong>.",
            "examples": [
                {
                    "en": "radio → radios",
                    "ua": "radio → radio"
                },
                {
                    "en": "video → videos",
                    "ua": "videos → videos"
                },
                {
                    "en": "zoo → zoos",
                    "ua": "zoo → zoos"
                },
                {
                    "en": "studio → studios",
                    "ua": "studio → studios"
                }
            ]
        },
        {
            "label": "Music and cuts → OS",
            "color": "sky",
            "description": "Musical terms and abbreviations always with <strong>-s</strong>.",
            "examples": [
                {
                    "en": "piano → pianos",
                    "ua": "piano → piano"
                },
                {
                    "en": "photo → photos",
                    "ua": "photo → photo"
                },
                {
                    "en": "kilo → kilos",
                    "ua": "kilograms → kilograms"
                }
            ],
            "note": "⚠️ Exceptions must be remembered!"
        }
    ]
}

{
    "title": "6. Nouns in -f/-fe → VES",
    "sections": [
        {
            "label": "F/FE → VES",
            "color": "rose",
            "description": "Many nouns in <strong>-f</strong> or <strong>-fe</strong> change the ending to <strong>-ves</strong>.",
            "examples": [
                {
                    "en": "knife → knives",
                    "ua": "knife → knives"
                },
                {
                    "en": "wife → wives",
                    "ua": "wife → wives"
                },
                {
                    "en": "leaf → leaves",
                    "ua": "leaf → leaves"
                },
                {
                    "en": "wolf → wolves",
                    "ua": "wolf → wolves"
                }
            ]
        },
        {
            "label": "More examples",
            "color": "amber",
            "description": "Other common nouns with this change:",
            "examples": [
                {
                    "en": "half → halves",
                    "ua": "half → halves"
                },
                {
                    "en": "shelf → shelves",
                    "ua": "shelf → shelves"
                },
                {
                    "en": "thief → thieves",
                    "ua": "thieves → thieves"
                },
                {
                    "en": "life → lives",
                    "ua": "life → life (pl.)"
                }
            ]
        },
        {
            "label": "Exceptions: only + S",
            "color": "sky",
            "description": "But some nouns with -f simply add <strong>-s</strong>:",
            "examples": [
                {
                    "en": "roof → roofs",
                    "ua": "dah → roofs"
                },
                {
                    "en": "chief → chiefs",
                    "ua": "leader → leaders"
                },
                {
                    "en": "belief → beliefs",
                    "ua": "belief → beliefs"
                }
            ],
            "note": "📌 These exceptions must be remembered!"
        }
    ]
}

{
    "title": "7. Irregular plurals",
    "sections": [
        {
            "label": "Vowel change",
            "color": "purple",
            "description": "Some nouns change <strong>internal vowel</strong>.",
            "examples": [
                {
                    "en": "man → men",
                    "ua": "man → men"
                },
                {
                    "en": "woman → women",
                    "ua": "woman → women"
                },
                {
                    "en": "foot → feet",
                    "ua": "foot → feet"
                },
                {
                    "en": "tooth → teeth",
                    "ua": "tooth → teeth"
                }
            ]
        },
        {
            "label": "Completely different form",
            "color": "rose",
            "description": "Some nouns have a <strong>completely different</strong> form plurals.",
            "examples": [
                {
                    "en": "child → children",
                    "ua": "child → children"
                },
                {
                    "en": "person → people",
                    "ua": "man → people"
                },
                {
                    "en": "mouse → mice",
                    "ua": "mouse → mice"
                },
                {
                    "en": "goose → geese",
                    "ua": "goose → geese"
                }
            ]
        },
        {
            "label": "Same form",
            "color": "emerald",
            "description": "Some nouns <strong>do not change</strong> in the plural.",
            "examples": [
                {
                    "en": "sheep → sheep",
                    "ua": "sheep → sheep"
                },
                {
                    "en": "fish → fish",
                    "ua": "fish → fish"
                },
                {
                    "en": "deer → deer",
                    "ua": "deer → deer"
                },
                {
                    "en": "series → series",
                    "ua": "series → series"
                }
            ],
            "note": "📌 Fish can be fishes if different species fish."
        }
    ]
}

{
    "title": "8. Comparison table of rules",
    "intro": "Basic rules of plural formation:",
    "rows": [
        {
            "en": "Most nouns",
            "ua": "Most nouns",
            "note": "+ s: cat → cats, book → books"
        },
        {
            "en": "After s, x, z, ch, sh",
            "ua": "After s, x, z, ch, sh",
            "note": "+ es: box → boxes, bus → buses"
        },
        {
            "en": "Consonant + y",
            "ua": "Consonant + y",
            "note": "y → ies: baby → babies, city → cities"
        },
        {
            "en": "Vowel + y",
            "ua": "Vowel + y",
            "note": "+ s: boy → boys, day → days"
        },
        {
            "en": "f / fe",
            "ua": "Ending f / fe",
            "note": "f/fe → ves: knife → knives, leaf → leaves"
        },
        {
            "en": "Irregular",
            "ua": "Irregular",
            "note": "man → men, child → children, sheep → sheep"
        }
    ],
    "warning": "📌 Irregular plural forms should be studied by heart!"
}

{
    "title": "9. Typical mistakes",
    "items": [
        {
            "label": "Mistake 1",
            "color": "rose",
            "title": "Forget about -es after sibilants.",
            "wrong": "two boxes, three buss",
            "right": " ✅ <span class="font-mono">two boxes, three buses</span>[[[CODX_10]]]Mistake 2"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "No change y to ies.",
            "wrong": "babys, cities",
            "right": "​​​​ <span class="font-mono">babies, cities</span>"
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Change y to ies after a vowel.",
            "wrong": "boys, daies",
            "right": "​​​​​​​​ feet</span>"
        },
        {
            "label": "Помилка 4",
            "color": "purple",
            "title": "Правильна форма неправильних іменників.",
            "wrong": "childs, mans, foots",
            "right": "✅ <span class="font-mono">children, men, feet</span>"
        }
    ]
}

{
    "title": "11. Practice",
    "select_title": "Exercise 1. Choose the correct plural form",
    "select_intro": "Choose the correct plural form for each noun.",
    "selects": [
        {
            "label": "cat → (cats / cates / caties)",
            "prompt": "What is the plural?"
        },
        {
            "label": "box → (boxes / boxes / boxies)",
            "prompt": "What is plural?"
        },
        {
            "label": "baby → (babys / babies / babes)",
            "prompt": "What is plural?"
        },
        {
            "label": "boy → (boies / boys / boyes)",
            "prompt": "What is plural?"
        }
    ],
    "options": [
        "First option",
        "Second option",
        "Third option"
    ],
    "input_title": "Exercise 2. Write the plural form",
    "input_intro": "Write the correct plural form for these nouns.",
    "inputs": [
        {
            "before": "child → ",
            "after": ""
        },
        {
            "before": "knife → ",
            "after": ""
        },
        {
            "before": "potato → ",
            "after": ""
        }
    ],
    "rephrase_title": "Exercise 3. Correct the error",
    "rephrase_intro": "Find and correct the error in the plural form.",
    "rephrase": [
        {
            "example_label": "Example:",
            "example_original": "I have two children.",
            "example_target": "I have two children."
        },
        {
            "original": "1. There are three boxes on the table.",
            "placeholder": "Fix the error"
        },
        {
            "original": "2. I visited five cities last summer.",
            "placeholder": "Fix the error"
        }
    ]
}

